import React, { useState, useEffect } from 'react';
import '../assets/styles/Zoom.css';
import RefreshIcon from '@mui/icons-material/Refresh';
import CloseIcon from '@mui/icons-material/Close';

const Zoom = () => {
  const [showConfirm, setShowConfirm] = useState(false);
  const [contacts, setContacts] = useState([]);
  const [error, setError] = useState('');

  // Fetch contacts from the backend
  const fetchContacts = () => {
    fetch('/shortcuts/zoom/get-contacts/')
      .then(response => response.json())
      .then(data => {
        if (data.success) {
          setContacts(data.contacts);
        } else {
          setError('Unable to fetch contacts');
        }
      })
      .catch(err => {
        setError('An error occurred while fetching contacts');
        console.error('Error:', err);
      });
  };

  useEffect(() => {
    fetchContacts();
  }, []);

  const handleRequest = (url) => {
    fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      }
    })
    .catch(error => {
      console.error('Error:', error);
    });
  };

  const handleActivateZoom = () => {
    handleRequest('/shortcuts/zoom/open-zoom/');
  };

  const handleCloseZoom = () => {
    handleRequest('/shortcuts/zoom/close-zoom/');
    setShowConfirm(false);
  };

  const confirmCloseZoom = () => {
    setShowConfirm(true);
  }

  return (
    <div className="zoom-container">
      <h1 className="title">Zoom</h1>
      
      {/* Show Zoom Contacts */}
      {error && <p className="error">{error}</p>}
      <ul className="contacts-list">
        {contacts.length > 0 ? (
          contacts.map((contact, index) => (
            <li key={index}>{contact.first_name} {contact.last_name}</li>
          ))
        ) : (
          <li>No contacts available</li>
        )}
      </ul>

      {/* Zoom Control Buttons */}
      <div className="button-container">
        <button onClick={handleActivateZoom} className="button activate-zoom-button">
          <RefreshIcon className="button-icon" /> Adu în față Zoom
        </button>
        
        <button onClick={confirmCloseZoom} className="button close-zoom-button">
          <CloseIcon className="button-icon" /> Închide Zoom
        </button>
      </div>

      {/* Confirmation Modal */}
      {showConfirm && (
        <div className="modal">
          <div className="modal-content">
            <p>Ești sigur că vrei să închizi Zoom?</p>
            <button onClick={handleCloseZoom} className="confirm-button">Da</button>
            <button onClick={() => setShowConfirm(false)} className="cancel-button">Nu</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Zoom;
